// src/Views/AiModelSuggestModel.ts
var import_obsidian10 = require("obsidian");
var AiModelSuggestModal = class extends import_obsidian10.SuggestModal {
  constructor(app, editor, editorService, modelNames = []) {
    super(app);
    this.modelNames = modelNames;
    this.editor = editor;
    this.editorService = editorService;
    this.limit = this.modelNames.length;
    if (this.modelNames.length > 0) {
      this.setPlaceholder("Select Large Language Model");
    } else {
      this.setPlaceholder("Loading available models...");
    }
  }
  getSuggestions(query) {
    return this.modelNames.filter((model) => model.toLowerCase().includes(query.toLowerCase()));
  }
  renderSuggestion(model, el) {
    el.createEl("div", { text: model });
  }
  async onChooseSuggestion(modelName, evt) {
    if (this.modelNames.indexOf(modelName) === -1 || this.modelNames.length === 0) {
      return;
    }
    new import_obsidian10.Notice(`Selected model: ${modelName}`);
    try {
      await this.editorService.setModel(this.editor, modelName);
    } catch (error) {
      console.error("[ChatMDCustom] Error setting model in frontmatter:", error);
      new import_obsidian10.Notice(`Error setting model: ${error.message}`);
    }
  }
};

